import{v as r,r as i,o as s,i as l,w as d,b as e,d as t,a as p}from"./index-6e7b20f4.js";const u={class:"markdown-body"},c=e("h1",{id:"grants-supporting-the-orthoptera-species-file",tabindex:"-1"},"Grants supporting the Orthoptera Species File",-1),h=e("p",null,"The OSF grants committee received and evaluated fourteen proposals by applicants from ten countries (Brazil, Bulgaria, Cameroon, Germany, Italy, Pakistan, Sri Lanka, Turkey, USA, Uzbekistan). Eight proposals listed below were funded. These have been selected based on the amount of data (images, specimen records, and sounds) expected to be added to the Orthoptera Species File. Also considered was the candidates’ expertise, if the proposal was related to a taxonomic research project, and the adequate budget",-1),m=e("h2",{id:"projects-funded-for-2024",tabindex:"-1"},"Projects funded for 2024",-1),f=e("ol",null,[e("li",null,[e("p",null,[t("Chobanov, Dragan (Institute of Biodiversity and Ecosystem Research, Bulgaria)."),e("br"),t(" Title: Orthoptera of the mountains and deserts of the Western and Central Palearctic")])]),e("li",null,[e("p",null,[t("Fianco, Marcos (Federal University of Paraná, Brazil)"),e("br"),t(" Title: The Tettigoniidae from Caatinga: inventory of katydids from neglected Brazilian semi-arid region")])]),e("li",null,[e("p",null,[t("Manori Goonatilake (Department of National Museums, Colombo, Sri Lanka)"),e("br"),t(" Title: Monograph for the Orthoptera of Sri Lanka: Digitization of Orthoptera type & non-type specimens deposited in the Department of National Museums, Sri Lanka.")])]),e("li",null,[e("p",null,[t("Mariño-Pérez Ricardo (Museum of Zoology, University of Michigan, USA)."),e("br"),t(" Title: Capitalize TaxonWorks in under-collected areas: Bioko Island in Equatorial Guinea and Lobéké National Park in Cameroon.")])]),e("li",null,[e("p",null,[t("Santos Martins Silva, Daniela (Miami University, Oxford, OH, USA)."),e("br"),t(" Title: Grasshoppers from Brazil: Photographic database of underrepresented taxa")])]),e("li",null,[e("p",null,[t("Siqueira, Adriano (Museu Nacional, Universidade Federal do Rio de Janeiro, Brazil)."),e("br"),t(" Title: Expedition on the unexplored Gryllacrididae fauna (Ensifera: Stenopelmatoidea) of the Fluminense Atlantic Forest, Rio de Janeiro: updating the OSF online catalog.")])]),e("li",null,[e("p",null,[t("Tarekegn Fite Duressa. (Staatliches Museum für Naturkunde Karlsruhe, Germany)."),e("br"),t(" Title: Photographic database of the unexplored African pygmy grasshoppers (Orthoptera: Tetrigidae) from Ethiopia: Specimens deposited in the Staatliches useum für Naturkunde Karlsruhe and Natural History Museum Stuttgart, Germany")])]),e("li",null,[e("p",null,[t("Zahid Sundus. Fatima (Tuz Zohra School and Post Graduate College Mansehra, Pakistan)."),e("br"),t(" Title: Preserving history: digitalizing Orthoptera type specimens at Natural History Museum (NHM), London")])])],-1),g=e("h2",{id:"grant-application-guidelines",tabindex:"-1"},"Grant application guidelines",-1),b=e("p",null,"Grants are available for a project as defined by the applicant. The project must involve benefit to the Orthoptera Species File. The usual benefit is the addition of images (photographs of the habitus and diagnostic details of type specimens, other reliably identified museum specimens, living individuals in natural habitats), sound recordings, and/or geo-referenced specimen records. Any proposal that solely focuses on fieldwork or other systematic research without direct benefits to OSF will not be considered. Projects may be proposed for periods of one to three years.",-1),y=e("p",null,"Funding availability for 2024 will be announced in October 2024.",-1),v=e("p",null,"The proposals should include:",-1),_=e("ol",null,[e("li",null,"Project description (not more than five pages): Title Significance (highlighting the new data that will be added to OSF, preferably to taxa currently lacking images, sound recordings, distribution records, etc.) Objectives, methods and activities Timetable"),e("li",null,"If applicable, provide summary of the research project related to the proposal"),e("li",null,"Curriculum vitae"),e("li",null,"Budget in US$ (including justification of trips to museums, fieldwork, photographic equipment)"),e("li",null,"If applicable, provide letter of agreement/acknowledgement to work with the collection from the corresponding institution/curator including permission to add the images to OSF.")],-1),k=e("p",null,"Preference will be given in relation to the amount of data added into OSF, i.e. the expected contribution to the considered taxa (dependent on already existing data). A detailed list of the species that are poorly illustrated in OSF and the data that is expected to be added as a result of the grant is highly recommended to be included in the proposal. Proposals involving images and sound recordings taken in the field will be funded depending on the “biogeographical value”, i.e. surveys in under-collected areas will be preferred over similar activities in well-worked terrain. Preference will be also",-1),w=e("p",null,"given to applicants who demonstrate knowledge of the taxa involved. The methods, e.g., techniques for capturing images, will be likewise considered in the evaluation. Also, priority will be given to applicants planning to document and photograph the types of Orthoptera species not yet documented by images in OSF, or who are planning to document the types from museums or other collections not easily accessible to researchers. Applications of curators for support of a qualified student to do this under his supervision will also be considered",-1),S=e("p",null,[e("strong",null,"Important"),t(": A short financial and tasks report will be required from each grantee once the funding period is finished. The tasks report will be in a format suitable for publishing in Metaleptea.")],-1),O=e("p",null,"If the candidate has received an OSF grant in a previous year, the tasks from the previous grant have to be finished and the report approved by the OSF Committee before applying for a new grant",-1),T={},C="",A=r({__name:"grants",setup(x,{expose:o}){return o({frontmatter:{},excerpt:void 0}),(F,M)=>{const a=i("address-maker"),n=i("markdown-layout");return s(),l(n,{frontmatter:T},{default:d(()=>[e("div",u,[c,h,m,f,g,e("p",null,[t("The Orthopterists’ Society in cooperation with the Illinois Natural History Survey provides funding for work in support of the Orthoptera Species File. Members of the Orthopterists’ Society are invited to apply. Applications should be sent to María Marta Cigliano ("),p(a,{class:"font-medium",items:["cigliano","fcnym","unlp","edu","ar"]}),t(").")]),b,y,v,_,k,w,S,O])]),_:1})}}});export{A as default,C as excerpt,T as frontmatter};
